-    scrubbed = scrubbed.replace(this.patterns.bearerToken, 'Bearer [TOKEN]');
-    scrubbed = scrubbed.replace(this.patterns.privateKey, '[PRIVATE_KEY]');
-
-    return scrubbed;
-  }
-}
-
-export const piiScrubber = new PIIScrubber();

